import os
from flask import Flask, request, jsonify, render_template, redirect, url_for
from pymongo import MongoClient
from pymongo.errors import ConnectionFailure, OperationFailure
from bson.objectid import ObjectId
from datetime import datetime

app = Flask(__name__)

# MongoDB Configuration
MONGO_URI = "mongodb://localhost:27017/"
DB_NAME = "cms_db"

client = None
db = None

def init_db():
    global client, db
    try:
        client = MongoClient(MONGO_URI)
        client.admin.command('ping') # Test connection
        db = client[DB_NAME]
        print("Connected to MongoDB successfully!")

        # Create unique indexes if they don't exist
        db.users.create_index("username", unique=True)
        db.documents.create_index("title")
        db.documents.create_index("author_id")
        db.documents.create_index("tags")

    except ConnectionFailure as e:
        print(f"MongoDB connection failed: {e}")
        # Optionally exit or handle more gracefully
        exit(1)
    except Exception as e:
        print(f"An unexpected error occurred during DB initialization: {e}")
        exit(1)

# Initialize DB on startup
with app.app_context():
    init_db()

# --- Utility Functions ---
def get_user_by_username(username):
    return db.users.find_one({"username": username})

def get_user_by_id(user_id):
    return db.users.find_one({"_id": ObjectId(user_id)})

# --- Error Handling ---
@app.errorhandler(404)
def not_found(error):
    return jsonify({"error": "Not found"}), 404

@app.errorhandler(500)
def internal_error(error):
    return jsonify({"error": "Internal server error"}), 500

# --- Routes ---

@app.route('/')
def index():
    return render_template('index.html')

# --- User Profile Management ---

@app.route('/users', methods=['POST'])
def create_user():
    data = request.json
    if not data or not data.get('username') or not data.get('email'):
        return jsonify({"error": "Username and email are required"}), 400

    if get_user_by_username(data['username']):
        return jsonify({"error": "Username already exists"}), 409

    user_data = {
        "username": data['username'],
        "email": data['email'],
        "full_name": data.get('full_name'),
        "bio": data.get('bio'),
        "created_at": datetime.utcnow(),
        "updated_at": datetime.utcnow()
    }
    try:
        result = db.users.insert_one(user_data)
        user_data['_id'] = str(result.inserted_id) # Convert ObjectId to string
        return jsonify({"message": "User created successfully", "user": user_data}), 201
    except OperationFailure as e:
        return jsonify({"error": f"Database operation failed: {e.details}"}), 500
    except Exception as e:
        return jsonify({"error": f"An unexpected error occurred: {str(e)}"}), 500

@app.route('/users', methods=['GET'])
def get_all_users():
    users = []
    for user in db.users.find({}):
        user['_id'] = str(user['_id'])
        users.append(user)
    return jsonify(users), 200

@app.route('/users/<user_id>', methods=['GET'])
def get_user(user_id):
    try:
        user = get_user_by_id(user_id)
        if user:
            user['_id'] = str(user['_id'])
            return jsonify(user), 200
        return jsonify({"error": "User not found"}), 404
    except Exception:
        return jsonify({"error": "Invalid User ID format"}), 400

@app.route('/users/<user_id>', methods=['PUT'])
def update_user(user_id):
    data = request.json
    if not data:
        return jsonify({"error": "No data provided for update"}), 400

    try:
        user = get_user_by_id(user_id)
        if not user:
            return jsonify({"error": "User not found"}), 404

        update_fields = {k: v for k, v in data.items() if k in ['email', 'full_name', 'bio']}
        if 'username' in data and data['username'] != user['username']:
            if get_user_by_username(data['username']):
                return jsonify({"error": "New username already exists"}), 409
            update_fields['username'] = data['username']

        if not update_fields:
            return jsonify({"message": "No valid fields to update"}), 200

        update_fields['updated_at'] = datetime.utcnow()

        result = db.users.update_one(
            {"_id": ObjectId(user_id)},
            {"$set": update_fields}
        )

        if result.modified_count == 1:
            updated_user = get_user_by_id(user_id)
            updated_user['_id'] = str(updated_user['_id'])
            return jsonify({"message": "User updated successfully", "user": updated_user}), 200
        return jsonify({"message": "User found, but no changes were made"}), 200

    except Exception:
        return jsonify({"error": "Invalid User ID format or other error"}), 400

@app.route('/users/<user_id>', methods=['DELETE'])
def delete_user(user_id):
    try:
        result = db.users.delete_one({"_id": ObjectId(user_id)})
        if result.deleted_count == 1:
            # Also delete documents authored by this user
            db.documents.delete_many({"author_id": user_id})
            return jsonify({"message": "User and their documents deleted successfully"}), 200
        return jsonify({"error": "User not found"}), 404
    except Exception:
        return jsonify({"error": "Invalid User ID format"}), 400

# --- Document Storage and Query ---

@app.route('/documents', methods=['POST'])
def create_document():
    data = request.json
    required_fields = ['title', 'content', 'author_id']
    if not all(field in data for field in required_fields):
        return jsonify({"error": f"Missing required fields: {', '.join(required_fields)}"}), 400

    # Verify author exists
    try:
        if not get_user_by_id(data['author_id']):
            return jsonify({"error": "Author not found"}), 404
    except Exception:
        return jsonify({"error": "Invalid Author ID format"}), 400

    document_data = {
        "title": data['title'],
        "content": data['content'],
        "author_id": data['author_id'],
        "tags": data.get('tags', []), # List of strings
        "status": data.get('status', 'draft'), # e.g., 'draft', 'published', 'archived'
        "created_at": datetime.utcnow(),
        "updated_at": datetime.utcnow(),
        "published_at": None
    }
    if document_data['status'] == 'published':
        document_data['published_at'] = datetime.utcnow()

    try:
        result = db.documents.insert_one(document_data)
        document_data['_id'] = str(result.inserted_id)
        return jsonify({"message": "Document created successfully", "document": document_data}), 201
    except OperationFailure as e:
        return jsonify({"error": f"Database operation failed: {e.details}"}), 500
    except Exception as e:
        return jsonify({"error": f"An unexpected error occurred: {str(e)}"}), 500

@app.route('/documents', methods=['GET'])
def get_documents():
    query = {}
    if 'author_id' in request.args:
        try:
            # Ensure author_id is valid before querying
            if not get_user_by_id(request.args['author_id']):
                return jsonify({"error": "Author not found"}), 404
            query['author_id'] = request.args['author_id']
        except Exception:
            return jsonify({"error": "Invalid Author ID format"}), 400
    if 'status' in request.args:
        query['status'] = request.args['status']
    if 'tag' in request.args:
        query['tags'] = request.args['tag']
    if 'search' in request.args:
        search_term = request.args['search']
        query['$or'] = [
            {"title": {"$regex": search_term, "$options": "i"}},
            {"content": {"$regex": search_term, "$options": "i"}}
        ]

    documents = []
    try:
        for doc in db.documents.find(query).sort("created_at", -1):
            doc['_id'] = str(doc['_id'])
            documents.append(doc)
        return jsonify(documents), 200
    except OperationFailure as e:
        return jsonify({"error": f"Database query failed: {e.details}"}), 500
    except Exception as e:
        return jsonify({"error": f"An unexpected error occurred: {str(e)}"}), 500

