@app.route('/documents/<doc_id>', methods=['PUT'])
def update_document(doc_id):
    data = request.json
    if not data:
        return jsonify({"error": "No data provided for update"}), 400

    try:
        doc = db.documents.find_one({"_id": ObjectId(doc_id)})
        if not doc:
            return jsonify({"error": "Document not found"}), 404

        update_fields = {}
        for key in ['title', 'content', 'tags', 'status']:
            if key in data:
                update_fields[key] = data[key]

        # Handle author_id change (optional, usually not changed, but if allowed)
        if 'author_id' in data and data['author_id'] != doc['author_id']:
            try:
                if not get_user_by_id(data['author_id']):
                    return jsonify({"error": "New author not found"}), 404
                update_fields['author_id'] = data['author_id']
            except Exception:
                return jsonify({"error": "Invalid New Author ID format"}), 400

        # Update published_at timestamp if status changes to 'published'
        if doc['status'] != 'published' and update_fields.get('status') == 'published':
            update_fields['published_at'] = datetime.utcnow()
        elif doc['status'] == 'published' and update_fields.get('status') != 'published':
            update_fields['published_at'] = None # Reset if unpublished

        if not update_fields:
            return jsonify({"message": "No valid fields to update"}), 200

        update_fields['updated_at'] = datetime.utcnow()

        result = db.documents.update_one(
            {"_id": ObjectId(doc_id)},
            {"$set": update_fields}
        )

        if result.modified_count == 1:
            updated_doc = db.documents.find_one({"_id": ObjectId(doc_id)})
            updated_doc['_id'] = str(updated_doc['_id'])
            return jsonify({"message": "Document updated successfully", "document": updated_doc}), 200
        return jsonify({"message": "Document found, but no changes were made"}), 200

    except Exception:
        return jsonify({"error": "Invalid Document ID format or other error"}), 400

