# --- Aggregation Pipelines ---

@app.route('/analytics/documents_by_status', methods=['GET'])
def documents_by_status():
    pipeline = [
        {"$group": {"_id": "$status", "count": {"$sum": 1}}},
        {"$sort": {"_id": 1}}
    ]
    result = list(db.documents.aggregate(pipeline))
    return jsonify(result), 200

@app.route('/analytics/documents_per_author', methods=['GET'])
def documents_per_author():
    pipeline = [
        {"$group": {"_id": "$author_id", "count": {"$sum": 1}}},
        {"$lookup": {
            "from": "users",
            "localField": "_id",
            "foreignField": "_id",
            "as": "author_info"
        }},
        {"$unwind": "$author_info"},
        {"$project": {
            "_id": 0,
            "author_id": {"$toString": "$_id"}, # Convert ObjectId to string for consistency
            "username": "$author_info.username",
            "full_name": "$author_info.full_name",
            "count": 1
        }},
        {"$sort": {"count": -1}}
    ]
    result = []
    for item in db.documents.aggregate(pipeline):
        # Convert _id from author_info (ObjectId) to string if present, otherwise just use author_id field directly
        # The author_id field in the $project stage is already a string, so this part needs careful handling
        # It's better to convert the author_info._id directly during the lookup or unwind stage if it's strictly needed
        # For now, just make sure the `_id` in the author_info itself is handled
        if 'author_info' in item and '_id' in item['author_info']:
             item['author_info']['_id'] = str(item['author_info']['_id'])
        result.append(item)
    return jsonify(result), 200


@app.route('/analytics/most_popular_tags', methods=['GET'])
def most_popular_tags():
    limit = int(request.args.get('limit', 10))
    pipeline = [
        {"$unwind": "$tags"},
        {"$group": {"_id": "$tags", "count": {"$sum": 1}}},
        {"$sort": {"count": -1}},
        {"$limit": limit}
    ]
    result = list(db.documents.aggregate(pipeline))
    return jsonify(result), 200

@app.route('/analytics/documents_last_7_days', methods=['GET'])
def documents_last_7_days():
    seven_days_ago = datetime.utcnow() - timedelta(days=7)
    pipeline = [
        {"$match": {"created_at": {"$gte": seven_days_ago}}},
        {"$group": {
            "_id": {
                "$dateToString": {"format": "%Y-%m-%d", "date": "$created_at"}
            },
            "count": {"$sum": 1}
        }},
        {"$sort": {"_id": 1}}
    ]
    result = list(db.documents.aggregate(pipeline))
    return jsonify(result), 200


